cat > /etc/nginx/conf.d/deploy.conf <<'EOF'
server {
    listen 8443 ssl;
    server_name localhost;

    ssl_certificate     /etc/nginx/ssl/self.crt;
    ssl_certificate_key /etc/nginx/ssl/self.key;

    root /var/www/deploy;
    index index.html;

    location / {
        try_files $uri $uri/ =404;
    }
}
EOF

cat > /git/project/hooks/post-receive <<'EOF'
#!/bin/bash
GIT_DIR=/git/project
MAIN_WT=/var/www/deploy
DEV_WT=/var/www/deploy/dev

while read oldrev newrev refname; do
    branch="${refname#refs/heads/}"
    case "$branch" in
        main)
            git --git-dir="$GIT_DIR" archive main | tar -x -C "$MAIN_WT"
            ;;
        dev)
            mkdir -p "$DEV_WT"
            git --git-dir="$GIT_DIR" archive dev | tar -x -C "$DEV_WT"
            ;;
    esac
done
EOF
chmod +x /git/project/hooks/post-receive
chown -R git:git /git/project /var/www/deploy
echo OK

